from math import isqrt
from Crypto.Util.number import *





e=65537 


def factorize(N):
    a = isqrt(N)
    b = a * a - N
    while b < 0 or not isqrt(b):
        a += 1
        b = a * a - N

    p = a - isqrt(b)
    q = N // p
    return p, q if p * q == N else None

p,q=factorize(n)
phi=(p-1)*(q-1)
d=pow(e,-1,phi)
m=pow(c,d,n)
print(long_to_bytes(m))